records.orchestrationConfig:
{
  "version": 1,
  "provider": "growthub-native",
  "nodes": [
    {
      "id": "input",
      "type": "input",
      "label": "Project input",
      "config": {
        "inputMode": "manual",
        "samplePayload": {
          "projectGid": "PROJECT_GID_PLACEHOLDER",
          "workspaceGid": "WORKSPACE_GID_PLACEHOLDER"
        }
      }
    },
    {
      "id": "active-tasks-call",
      "type": "api-registry-call",
      "label": "Pull active project tasks",
      "config": {
        "registryId": "asana-active-tasks",
        "integrationId": "asana-active-tasks",
        "method": "POST",
        "baseUrl": "http://127.0.0.1:3000",
        "endpoint": "/api/workspace/integrations/nango/proxy",
        "authRef": "NANGO_SECRET_KEY",
        "bodyTemplate": {
          "providerConfigKey": "asana",
          "connectionId": "CONNECTION_ID_PLACEHOLDER",
          "method": "GET",
          "path": "/api/1.0/projects/{{input.projectGid}}/tasks",
          "params": {
            "completed_since": "now",
            "limit": "20",
            "opt_fields": "gid,name,completed,assignee.name,due_on,permalink_url,created_at,modified_at,memberships.section.name"
          }
        },
        "deltaTags": [
          "routing",
          "input",
          "output"
        ]
      }
    },
    {
      "id": "normalize-active-tasks",
      "type": "transform-filter",
      "label": "Normalize active tasks",
      "config": {
        "rootPath": "data",
        "filter": {
          "completed": false
        },
        "fieldMap": {
          "gid": "gid",
          "name": "name",
          "completed": "completed",
          "assignee": "assignee.name",
          "due_on": "due_on",
          "section": "memberships.0.section.name",
          "permalink_url": "permalink_url",
          "modified_at": "modified_at"
        },
        "deltaTags": [
          "evaluation",
          "output"
        ]
      }
    },
    {
      "id": "result",
      "type": "tool-result",
      "label": "Persist task response",
      "config": {
        "saveStatus": true,
        "saveResponse": true,
        "sourceId": "project-active-tasks",
        "deltaTags": [
          "output"
        ]
      }
    }
  ],
  "edges": [
    {
      "from": "input",
      "to": "active-tasks-call",
      "passes": "input"
    },
    {
      "from": "active-tasks-call",
      "to": "normalize-active-tasks",
      "passes": "response"
    },
    {
      "from": "normalize-active-tasks",
      "to": "result",
      "passes": "normalized-output"
    }
  ]
}
